function _dlGetActiveImageMode(){const generateToggleEl=document.getElementById('downloadImgGenerateByFieldToggle');const renameToggleEl=document.getElementById('downloadImgRenameToggle');if(generateToggleEl&&!generateToggleEl.disabled&&generateToggleEl.checked&&_dlCanUseGenerateMode())return'generate';if(renameToggleEl&&!renameToggleEl.disabled&&renameToggleEl.checked&&_dlCanUseRenameMode())return'rename';return'';}
