function isImageFieldLocal(type,name){var t=String(type||'').toLowerCase();var n=String(name||'').toLowerCase();if(t==='image'||t==='photo'||t==='file')return true;if(n.indexOf('designation')!==-1)return false;if(t.indexOf('image')!==-1||t.indexOf('photo')!==-1||t.indexOf('file')!==-1||t.indexOf('upload')!==-1)return true;return n.indexOf('photo')!==-1||n.indexOf('image')!==-1||n.indexOf('picture')!==-1||n.indexOf('pic')!==-1||n.indexOf('img')!==-1||n.indexOf('signature')!==-1||n.indexOf('barcode')!==-1||n.indexOf('qr')!==-1;}
