function initializeInlineOriginalsFromDom(){resetInlineDirtyState();var inputs=confirmPreview?confirmPreview.querySelectorAll('.reprint-preview-input[data-field-name]'):[];inputs.forEach(function(inputEl){var key=String(inputEl.getAttribute('data-field-name')||'').trim();if(!key)return;var originalValue=String(inputEl.getAttribute('data-original-value')||'').trim();inlineOriginalFieldData[key]=originalValue;});}
function recomputeInlineDirtyState(){var count=0;var inputs=confirmPreview?confirmPreview.querySelectorAll('.reprint-preview-input[data-field-name]'):[];inputs.forEach(function(inputEl){var key=String(inputEl.getAttribute('data-field-name')||'').trim();if(!key)return;var currentVal=String(inputEl.value||'').trim();var originalVal=String(inlineOriginalFieldData[key]||'').trim();var isDirty=currentVal!==originalVal;var wrap=inputEl.closest('.reprint-preview-meta-item');if(wrap)wrap.classList.toggle('is-dirty',isDirty);if(isDirty)count+=1;});inlineDirtyCount=count;updateDirtyCountLabel();}
