function initKeyboardShortcuts(){document.addEventListener('keydown',function(e){if((e.ctrlKey||e.metaKey)&&e.key==='f'){const searchInput=document.getElementById('searchInput');if(searchInput){e.preventDefault();searchInput.focus();searchInput.select();}}
if(e.key==='Escape'){const sideModal=document.getElementById('sideModalOverlay');if(sideModal&&sideModal.classList.contains('active')){if(typeof closeSideModal==='function')closeSideModal();e.preventDefault();return;}
const deleteModal=document.getElementById('deleteModalOverlay');if(deleteModal&&deleteModal.classList.contains('active')){if(typeof closeDeleteModalFn==='function')closeDeleteModalFn();else deleteModal.classList.remove('active');document.body.style.overflow='';e.preventDefault();return;}
const simpleDeleteModal=document.getElementById('simpleDeleteModalOverlay');if(simpleDeleteModal&&simpleDeleteModal.classList.contains('active')){if(typeof closeSimpleDeleteModalFn==='function')closeSimpleDeleteModalFn();else simpleDeleteModal.classList.remove('active');document.body.style.overflow='';e.preventDefault();return;}
const uploadModal=document.getElementById('uploadModalOverlay');if(uploadModal&&uploadModal.classList.contains('active')){uploadModal.classList.remove('active');document.body.style.overflow='';e.preventDefault();return;}
const imageSortModal=document.getElementById('imageSortModalOverlay');if(imageSortModal&&imageSortModal.classList.contains('active')){imageSortModal.classList.remove('active');e.preventDefault();return;}
const searchAllModal=document.getElementById('searchAllModalOverlay');if(searchAllModal&&searchAllModal.classList.contains('active')){searchAllModal.classList.remove('active');e.preventDefault();return;}
const docFormatModal=document.getElementById('docFormatModalOverlay');if(docFormatModal&&docFormatModal.classList.contains('active')){docFormatModal.classList.remove('active');e.preventDefault();return;}}
if((e.ctrlKey||e.metaKey)&&e.key==='a'){const activeElement=document.activeElement;if(!activeElement.matches('input, textarea')){const selectAllCheckbox=document.getElementById('selectAll');if(selectAllCheckbox){e.preventDefault();selectAllCheckbox.checked=true;selectAllCheckbox.dispatchEvent(new Event('change',{bubbles:true}));}}}
if(e.key==='n'&&!e.ctrlKey&&!e.metaKey&&!e.altKey){const activeElement=document.activeElement;if(!activeElement.matches('input, textarea')){const addBtn=document.getElementById('addNewBtn');if(addBtn){e.preventDefault();addBtn.click();}}}
if(e.key==='t'&&!e.ctrlKey&&!e.metaKey&&!e.altKey){const activeElement=document.activeElement;if(!activeElement.matches('input, textarea')){e.preventDefault();goToTableTop();}}
if(e.key==='b'&&!e.ctrlKey&&!e.metaKey&&!e.altKey){const activeElement=document.activeElement;if(!activeElement.matches('input, textarea')){e.preventDefault();goToTableBottom();}}});}
function goToTableTop(){const tableBody=document.getElementById('cardsTableBody');const tableContainer=document.querySelector('.table-container');if(tableBody&&tableContainer){tableContainer.scrollTop=0;const firstRow=tableBody.querySelector('tr');if(firstRow){document.querySelectorAll('#cardsTableBody tr.selected').forEach(row=>{row.classList.remove('selected');const checkbox=row.querySelector('.rowCheckbox');if(checkbox)checkbox.checked=false;});firstRow.classList.add('selected');const checkbox=firstRow.querySelector('.rowCheckbox');if(checkbox)checkbox.checked=true;if(typeof window.IDCardApp.updateButtonStates==='function'){window.IDCardApp.updateButtonStates();}
firstRow.scrollIntoView({behavior:'smooth',block:'center'});}}}
